import React from 'react';
import PropTypes from 'prop-types';
import {
    Col,
    Form,
    Button, ButtonGroup,
    // ToggleButton, Modal,
    // Row, Container, Table, Pagination, InputGroup, FormControl,
} from 'react-bootstrap';
import Switch from "react-switch";

const config = require('../config.js');
const forge = require('node-forge');

export default class UserForm extends React.Component {

    constructor(...args) {
        super(...args);

        if (this.props.newRecord) {
            this.state = {
                code: "",
                name: "",
                email: "",
                password: '',
                password2: '',
                address: "",
                tel1: "",
                tel2: "",
                unit: "",
                division: "",
                note: "",
                isAdmin: false
            }
            this.state = {
                code: "0000",
                name: "ชยพล เหมาะเหม็ง",
                email: "mchayapol@gmail.com",
                password: 'a',
                password2: 'aa',
                address: "700/309 ม.6 ต.ดอนหัวฬ่อ อ.เมือง จ.ชลบุรี 20000",
                tel1: "038-214805-6",
                tel2: "086-0402413",
                unit: "ME",
                division: "MT",
                note: "",
                isAdmin: false
            }
        } else {
            // (this.props.data && this.props.data.name) 
            this.state = this.props.data;
            // this.state.isAdmin = (this.state.isAdmin == 'true')
            console.log("UserForm", this.state)
            // if (this.props.newRecord) {
            //     this.setState({
            //         password2: this.state.password
            //     });
            // }
        }

    }
    changeHandler = (e) => {

        this.setState({
            [e.target.id]: e.target.value
        })
    }

    handleSwitch = (checked) => {
        // console.log(el, state);        
        this.setState({ isAdmin: checked })
    }

    submitHandler = event => {
        const form = event.currentTarget;
        event.preventDefault();
        if (form.checkValidity() === false) {
            event.stopPropagation();
        }

        // Confirm password
        // if (this.props.newRecord) {
        //     if (this.state.password !== this.state.password2) {
        //         // event.stopPropagation();
        //         alert("Passwords don't match");
        //         return;
        //     }
        // }


        let user = this.state;
        let responseStatus;


        let method;
        if (this.props.newRecord) {
            method = 'POST';
            var md = forge.md.sha256.create();
            md.update(user.password);
            user.password = md.digest().toHex();
        } else {
            method = 'PUT';
            delete user.password;
        }
        console.log("submitHandler:", method, this.state);


        fetch(config.apiUrl + 'user', {
            method: method,
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            body: JSON.stringify(user)
        })
            .then(response => {
                responseStatus = response.ok;
                return response.json();
            })
            .then(jsonData => {
                console.log(responseStatus, JSON.stringify(jsonData));
                if (responseStatus) {
                    this.props.closeFormHandler(true, "สร้างผู้ใช้สำเร็จ");
                } else {
                    let msg;
                    if (jsonData.code === 11000) {
                        msg = 'ผิดพลาด รหัสซ้ำ';
                    } else {
                        msg = jsonData.errmsg;
                    }
                    this.props.closeFormHandler(true, msg);
                }
            })
            .catch(error => {
                console.error('Error:', error);
                this.props.closeFormHandler(false);
            });

    };

    render() {
        return (
            <Form onSubmit={this.submitHandler}>
                <Form.Row>
                    <Col xs={4}>
                        <Form.Group as={Col} controlId="code">
                            <Form.Label>หมายเลขประจำตัว</Form.Label>
                            <Form.Control type="text" placeholder="Code"
                                value={this.state.code}
                                onChange={this.changeHandler} />
                        </Form.Group>
                    </Col>
                    <Col xs={8}>
                        <Form.Group controlId="name">
                            <Form.Label>ชื่อ</Form.Label>
                            <Form.Control placeholder="ชื่อ"
                                value={this.state.name}
                                onChange={this.changeHandler} />
                        </Form.Group>
                    </Col>
                </Form.Row>

                <Form.Group controlId="isAdmin">
                    <Form.Label>Admin</Form.Label>
                    <Col xs={8}>
                        <Switch
                            onChange={this.handleSwitch}
                            // value={this.state.isAdmin}
                            checked={this.state.isAdmin}
                            name='isAdmin' />
                    </Col>
                </Form.Group>

                <Form.Group controlId="address">
                    <Form.Label>ที่อยู่</Form.Label>
                    <Form.Control placeholder="ที่อยู่"
                        value={this.state.address}
                        onChange={this.changeHandler} />

                </Form.Group>

                <Form.Group controlId="note">
                    <Form.Label>รายละเอียด</Form.Label>
                    <Form.Control placeholder="รายละเอียด"
                        value={this.state.note}
                        onChange={this.changeHandler} />
                </Form.Group>

                <Form.Row>
                    <Col xs={6}>
                        <Form.Group controlId="unit">
                            <Form.Label>UNIT</Form.Label>
                            <Form.Control placeholder="UNIT"
                                value={this.state.unit}
                                onChange={this.changeHandler} />
                        </Form.Group>
                    </Col>
                    <Col xs={6}>
                        <Form.Group controlId="division">
                            <Form.Label>Division</Form.Label>
                            <Form.Control placeholder="Division"
                                value={this.state.division}
                                onChange={this.changeHandler} />
                        </Form.Group>
                    </Col>
                </Form.Row>

                <Form.Row>
                    <Col xs={6}>
                        <Form.Group controlId="tel1">
                            <Form.Label>โทร 1</Form.Label>
                            <Form.Control placeholder="โทร 1"
                                value={this.state.tel1}
                                onChange={this.changeHandler} />
                        </Form.Group>
                    </Col>
                    <Col xs={6}>
                        <Form.Group controlId="tel2">
                            <Form.Label>โทร 2</Form.Label>
                            <Form.Control placeholder="โทร 2"
                                value={this.state.tel2}
                                onChange={this.changeHandler} />
                        </Form.Group>
                    </Col>
                </Form.Row>

                {this.props.newRecord && <h3>ข้อมูลสำหรับเข้าระบบ</h3>}
                <Form.Group controlId="email">
                    <Form.Label>e-mail</Form.Label>
                    <Form.Control placeholder="e-mail"
                        required
                        value={this.state.email}
                        onChange={this.changeHandler} />
                </Form.Group>
                {this.props.newRecord &&
                    <>
                        <Form.Group controlId="password">
                            <Form.Label>Password</Form.Label>
                            <Form.Control placeholder="Password"
                                type="password"
                                required
                                value={this.state.password}
                                onChange={this.changeHandler} />
                        </Form.Group>
                        {/* <Form.Group controlId="password2">
                            <Form.Label>ยืนยัน Password</Form.Label>
                            <Form.Control placeholder="ยืนยัน Password"
                                required
                                value={this.state.password2}
                                onChange={this.changeHandler} />
                        </Form.Group> */}
                    </>
                }


                <div className="d-flex flex-column">
                    <ButtonGroup >
                        <Button variant="success" type="submit">
                            บันทึก
                </Button>
                        <Button variant="outline-secondary"
                            onClick={this.props.closeFormHandler}>
                            ยกเลิก
                </Button>
                    </ButtonGroup>
                </div>
            </Form>
        );
    }
}

UserForm.propTypes = {
    newRecord: PropTypes.bool
};